#!/usr/bin/env node

/*
 * sync-html-templates.mjs
 *
 * Reads shared CSS/JS/HTML sources from lib/html-ui/ and generates
 * self-contained template files. All templates are deterministic:
 * same sources produce identical output.
 *
 * Do not edit generated templates directly.
 */

import { readFileSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = resolve(__dirname, '..');

// ===== Source files =====

const uiDir = resolve(root, 'lib', 'html-ui');

function readPart(name) {
  return readFileSync(resolve(uiDir, name), 'utf8');
}

const tokensCss = readPart('tokens.css');
const commonCss = readPart('common.css');
const brainstormCss = readPart('brainstorm.css');
const documentCss = readPart('document.css');
const documentThemeJs = readPart('document-theme.js');
const baseFrame = readFileSync(resolve(uiDir, 'base-frame.html'), 'utf8');

// ===== Output definitions =====

const BANNER = '<!-- Generated by scripts/sync-html-templates.mjs. Do not edit directly. -->\n';

const outputs = [
  {
    name: 'brainstorm',
    out: 'skills/brainstorming/scripts/frame-template.html',
    templateKind: 'brainstorm',
    bodyClass: '',
    title: 'Softpowers Brainstorming',
    styles: [tokensCss, commonCss, brainstormCss],
    scripts: '',
    header: `
<div class="sp-header">
  <h1><a href="https://github.com/bnema/softpowers" style="color: inherit; text-decoration: none;">Softpowers Brainstorming</a></h1>
  <div class="status">Connected</div>
</div>`,
    footer: `
<div class="indicator-bar">
  <span id="indicator-text">Click an option above, then return to the terminal</span>
</div>`,
  },
  {
    name: 'spec',
    out: 'templates/spec.template.html',
    templateKind: 'spec',
    bodyClass: 'sp-doc',
    title: '{{DOC_TITLE}}',
    styles: [tokensCss, commonCss, documentCss],
    scripts: documentThemeJs,
    header: `
<div class="sp-header">
  <h1><a href="https://github.com/bnema/softpowers" style="color: inherit; text-decoration: none;">Softpowers Spec</a></h1>
</div>`,
    footer: '',
  },
  {
    name: 'plan',
    out: 'templates/plan.template.html',
    templateKind: 'plan',
    bodyClass: 'sp-doc',
    title: '{{DOC_TITLE}}',
    styles: [tokensCss, commonCss, documentCss],
    scripts: documentThemeJs,
    header: `
<div class="sp-header">
  <h1><a href="https://github.com/bnema/softpowers" style="color: inherit; text-decoration: none;">Softpowers Plan</a></h1>
</div>`,
    footer: '',
  },
];

function inlineCss(parts) {
  return parts.join('\n\n');
}

function buildTemplate(def) {
  const styleBlock = '<style>\n' + inlineCss(def.styles) + '\n</style>';
  const scriptBlock = def.scripts ? '<script>\n' + def.scripts + '\n</script>' : '';

  // The brainstorming server expects <!-- CONTENT --> (HTML comment), not {{CONTENT}}.
  // Additionally, the server test asserts id="claude-content" on the container.
  // Spec/plan templates use {{CONTENT}} as a conventional mustache placeholder.
  const contentPlaceholder = def.name === 'brainstorm' ? '<div id="claude-content"><!-- CONTENT --></div>' : '{{CONTENT}}';

  let html = baseFrame
    .replace('{{DOC_TITLE}}', def.title)
    .replace('{{STYLES}}', styleBlock)
    .replace('{{HEAD_EXTRAS}}', '')
    .replace('{{BODY_CLASS}}', def.bodyClass)
    .replace('{{TEMPLATE_KIND}}', def.templateKind)
    .replace('{{HEADER}}', def.header)
    .replace('{{CONTENT}}', contentPlaceholder)
    .replace('{{FOOTER}}', def.footer)
    .replace('{{SCRIPTS}}', scriptBlock);

  return BANNER + html.trim() + '\n';
}

// ===== Generate =====

for (const def of outputs) {
  const outPath = resolve(root, def.out);
  writeFileSync(outPath, buildTemplate(def), 'utf8');
  console.log('Wrote: ' + def.out);
}

console.log('Done.');
